# -- Equations --
Equations <- function(t) {
#Households
Y_HG[t] <<- W[t]+DP[t]+BP[t]+int_D*D[t-1]+int_S*SEC_H[t-1] #Gross disposable income of households
W[t] <<- s_W*Y[t] #Wage income
Y_H[t] <<- Y_HG[t]-TAX_H[t] #Disposable income of households
CO_PRI[t] <<- c_1*Y_H[t-1]+c_2*V_H[t-1] #Private consumption expenditures
SEC_H[t] <<- lambda*V_H[t-1] #Government securities held by households
V_H[t] <<- SEC_H[t]+D[t] #Household wealth
D[t] <<- D[t-1]+Y_H[t]-CO_PRI[t]-(SEC_H[t]-SEC_H[t-1]) #Deposits #redundant
 
#Firms
Y[t] <<- CO_PRI[t]+I[t]+CO_GOV[t] #Nominal output
TP_G[t] <<- Y[t]-W[t]-int_C*L_C[t-1]-int_G*L_G[t-1] #Gross profits of firms
TP[t] <<- TP_G[t]-TAX_F[t]-TAX_C[t]+SUB[t] #Total profits of firms
RP[t] <<- s_F*TP[t] #Retained profits
DP[t] <<- TP[t]-RP[t] #Distributed profits
I[t] <<- (alpha_0+alpha_1*r[t-1])*K[t-1] #Investment
r[t] <<- TP[t]/K[t] #Rate of profit
I_G[t] <<- beta[t]*I[t] #Green investment
beta[t] <<- beta_0-beta_1*(int_G-int_C)+beta_2*tucf[t-1]+beta_3*gov_SUB #Share of green investment in total investment
tucf[t] <<- pucf+tau_C*omega #Total unit cost of fossil energy production
I_C[t] <<- I[t]-I_G[t] #Conventional investment
K_G[t] <<- K_G[t-1]+I_G[t] #Green capital stock
K_C[t] <<- K_C[t-1]+I_C[t] #Conventional capital stock
K[t] <<- K_C[t]+K_G[t] #Capital stock
L_G[t] <<- L_G[t-1]+I_G[t]-beta[t]*RP[t] #Green loans (USD trillion)
L_C[t] <<- L_C[t-1]+I_C[t]+I_G[t]-RP[t]-(L_G[t]-L_G[t-1]) #Conventional loans (USD trillion)
L[t] <<- L_C[t]+L_G[t] #Total loans (USD trillion)
 
#Banks
BP[t] <<- int_C*L_C[t-1]+int_G*L_G[t-1]+int_S*SEC_B[t-1]-int_D*D[t-1] #Profits of banks
SEC_B[t] <<- D[t]-L_G[t]-L_C[t] #Government securities held by banks
SEC_Bred[t] <<- SEC[t]-SEC_H[t] #Redundant government securities held by banks
 
#Government
SEC[t] <<- SEC[t-1]+int_S*SEC[t-1]-TAX[t]+SUB[t]+CO_GOV[t] #Government securities
CO_GOV[t] <<- gov_C*Y[t-1] #Government expenditure
SUB[t] <<- gov_SUB*I_G[t-1] #Green government subsidies
TAX_H[t] <<- tau_H*Y_HG[t-1] #Taxes on households
TAX_F[t] <<- tau_F*TP_G[t-1] #Taxes on firms' profits
TAX_C[t] <<- tau_C*EMIS_F[t-1] #Carbon tax revenues
TAX[t] <<- TAX_H[t]+TAX_F[t]+TAX_C[t] #Total taxes
 
#Emissions
EMIS_F[t] <<- CI[t]*Y[t] #Fossil carbon emissions
CI[t] <<- CI_min+(CI_max-CI_min)/(1+((K_G[t-1]/K_C[t-1])/c_CI)^k_CI) #Carbon intensity
 
#Auxiliary equations
Y_P[t] <<- v*K[t] #Potential output
u[t] <<- Y[t]/Y_P[t] #Capacity utilisation rate
g_Y[t] <<- (Y[t]-Y[t-1])/Y[t-1] #Growth rate of output
lev[t] <<- L[t]/K[t] #Leverage ratio
SEC_Y[t] <<- SEC[t]/Y[t] #Government securities-to-GDP ratio
#Supplementary growth equations
g_D[t] <<- (D[t]-D[t-1])/D[t-1] #Growth rate of deposits
g_L[t] <<- (L[t]-L[t-1])/L[t-1] #Growth rate of total loans
g_LG[t] <<- (L_G[t]-L_G[t-1])/L_G[t-1] #Growth rate of green loans
g_LC[t] <<- (L_C[t]-L_C[t-1])/L_C[t-1] #Growth rate of conventional loans
g_K[t] <<- (K[t]-K[t-1])/K[t-1] #Growth rate of capital stock
g_KG[t] <<- (K_G[t]-K_G[t-1])/K_G[t-1] #Growth rate of green capital stock
g_KC[t] <<- (K_C[t]-K_C[t-1])/K_C[t-1] #Growth rate of conventional capital stock
g_YH[t] <<- (Y_H[t]-Y_H[t-1])/Y_H[t-1] #Growth rate of disposable household income
g_YHG[t] <<- (Y_HG[t]-Y_HG[t-1])/Y_HG[t-1] #Growth rate of gross household income
g_IG[t] <<- (I_G[t]-I_G[t-1])/I_G[t-1] #Growth rate of green investment
g_TPG[t] <<- (TP_G[t]-TP_G[t-1])/TP_G[t-1] #Growth rate of gross profits
g_SECH[t] <<- (SEC_H[t]-SEC_H[t-1])/SEC_H[t-1] #Growth rate of household-held government securities
g_SECB[t] <<- (SEC_B[t]-SEC_B[t-1])/SEC_B[t-1] #Growth rate of bank-held government securities
g_SEC[t] <<- (SEC[t]-SEC[t-1])/SEC[t-1] #Growth rate of government securities
g_EMISF[t] <<- (EMIS_F[t]-EMIS_F[t-1])/EMIS_F[t-1] #Growth rate of emissions
g_VH[t] <<- (V_H[t]-V_H[t-1])/V_H[t-1] #Growth rate of household wealth
}

# -- Initial Values (generated) --
