  beta_2 <<- 20  # free
  beta_3 <<- 1  # free
  tau_F <<- 0.15  # free
  int_S <<- 0.0254  # free
  pucf <<- 0.021  # free
  omega <<- 0.072  # free
  Y[1] <<- 106.94  # free
  I[1] <<- 0.259*Y[1]  # free
  L[1] <<- 0.93*Y[1]  # free
  u[1] <<- 0.73  # free
  I_G[1] <<- 1.78  # free
  EMIS_F[1] <<- 37.82  # free
  D[1] <<- 130  # free
  SUB[1] <<- 0.14  # free
  CO_GOV[1] <<- 0.17*Y[1]  # free
  SEC[1] <<- 0.94*Y[1]  # free
  TAX_C[1] <<- 0.104  # free
  g_Y[1] <<- 0.029  # free
  g_D[1] <<- g_Y[1]  # free
  g_L[1] <<- g_Y[1]  # free
  g_K[1] <<- g_Y[1]  # free
  g_YH[1] <<- g_Y[1]  # free
  g_LG[1] <<- g_Y[1]  # free
  g_LC[1] <<- g_Y[1]  # free
  g_KG[1] <<- g_Y[1]  # free
  g_KC[1] <<- g_Y[1]  # free
  g_IG[1] <<- g_Y[1]  # free
  g_TPG[1] <<- g_Y[1]  # free
  g_YHG[1] <<- g_Y[1]  # free
  g_SECH[1] <<- g_Y[1]  # free
  g_SECB[1] <<- g_Y[1]  # free
  g_SEC[1] <<- g_Y[1]  # free
  g_VH[1] <<- g_Y[1]  # free
  g_EMISF[1] <<- g_Y[1]  # free
  CI_2050 <<- 0.8*CI[1]  # free
  KG_KC2049 <<- K_G[1]/K_C[1]+26*0.01  # free
  CI_max <<- 1.2*CI[1]  # free
  CI_min <<- 0.5*CI[1]  # free
  k_CI <<- (log((1/((CI_2050-CI_min)/(CI_max-CI_min)))-1)-log((1/((CI[1]-CI_min)/(CI_max-CI_min)))-1))/(log(KG_KC2049)-log((K_G[1]/(1+g_KG[1]))/(K_C[1]/(1+g_KC[1]))))  # free
  SEC_Bred[1] <<- SEC_B[1]  # free

  # -- Model-constrained (solved in dependency order) --
  c_CI <<- (K_G[1]/K_C[1]) / ((CI_max-CI_min)/(CI[1]-CI_min) - 1)^(1/k_CI)  #Calculated using Eq. (CI)
  W[1] <<- s_W*Y[1]  #Calculated using Eq. (W)
  CO_PRI[1] <<- (Y[1] -  (I[1]) -  (CO_GOV[1]))  #Calculated using Eq. (Y)
  SEC_H[1] <<- (- SEC_Bred[1] + SEC[1])  #Calculated using Eq. (SEC_Bred)
  V_H[1] <<- SEC_H[1]+D[1]  #Calculated using Eq. (V_H)
  beta[1] <<- (I_G[1]) / (I[1])  #Calculated using Eq. (I_G)
  I_C[1] <<- I[1]-I_G[1]  #Calculated using Eq. (I_C)
  K_G[1] <<- I_G[1] / (1 - (1 / ((1 + g_KG[1]))))  #Calculated using Eq. (K_G)
  K_C[1] <<- I_C[1] / (1 - (1 / ((1 + g_KC[1]))))  #Calculated using Eq. (K_C)
  K[1] <<- K_C[1]+K_G[1]  #Calculated using Eq. (K)
  TAX[1] <<- (- SEC[1] + (SEC[1] / (1 + g_SEC[1])) + int_S*(SEC[1] / (1 + g_SEC[1])) + SUB[1] + CO_GOV[1])  #Calculated using Eq. (SEC)
  CI[1] <<- (EMIS_F[1]) / (Y[1])  #Calculated using Eq. (EMIS_F)
  Y_P[1] <<- (Y[1]) / (u[1])  #Calculated using Eq. (u)
  lev[1] <<- L[1]/K[1]  #Calculated using Eq. (lev)
  SEC_Y[1] <<- SEC[1]/Y[1]  #Calculated using Eq. (SEC_Y)
  lambda <<- (SEC_H[1]) / ((V_H[1] / (1 + g_VH[1])))  #Calculated using Eq. (SEC_H)
  gov_SUB <<- (SUB[1]) / ((I_G[1] / (1 + g_IG[1])))  #Calculated using Eq. (SUB)
  tau_C <<- (TAX_C[1]) / ((EMIS_F[1] / (1 + g_EMISF[1])))  #Calculated using Eq. (TAX_C)
  tucf[1] <<- pucf+tau_C*omega  #Calculated using Eq. (tucf)
  beta_0 <<- (beta[1] + (beta_1*(int_G-int_C)) -  (beta_2*tucf[1]) -  (beta_3*gov_SUB))  #Calculated using Eq. (beta)
  gov_C <<- (CO_GOV[1]) / ((Y[1] / (1 + g_Y[1])))  #Calculated using Eq. (CO_GOV)
  v <<- (Y_P[1]) / (K[1])  #Calculated using Eq. (Y_P)
  c_1 <<- (CO_PRI[1] -  (c_2*(V_H[1] / (1 + g_VH[1])))) / ((Y_H[1] / (1 + g_YH[1])))  #Calculated using Eq. (CO_PRI)
  s_F <<- (RP[1]) / (TP[1])  #Calculated using Eq. (RP)
  DP[1] <<- 8.8188  #Calculated using Eq. (DP (block solve))
  TP[1] <<- 33.7134  #Calculated using Eq. (TP (block solve))
  RP[1] <<- 24.8946  #Calculated using Eq. (L_G (block solve))
  TP_G[1] <<- 39.4244  #Calculated using Eq. (TP_G (block solve))
  TAX_F[1] <<- 5.747  #Calculated using Eq. (TAX_F (block solve))
  L_G[1] <<- 6.3915  #Calculated using Eq. (L_C (block solve))
  L_C[1] <<- 93.0627  #Calculated using Eq. (L (block solve))
  r[1] <<- TP[1]/K[1]  #Calculated using Eq. (r)
  SEC_B[1] <<- D[1]-L_G[1]-L_C[1]  #Calculated using Eq. (SEC_B)
  BP[1] <<- int_C*(L_C[1] / (1 + g_LC[1]))+int_G*(L_G[1] / (1 + g_LG[1]))+int_S*(SEC_B[1] / (1 + g_SECB[1]))-int_D*(D[1] / (1 + g_D[1]))  #Calculated using Eq. (BP)
  Y_HG[1] <<- W[1]+DP[1]+BP[1]+int_D*(D[1] / (1 + g_D[1]))+int_S*(SEC_H[1] / (1 + g_SECH[1]))  #Calculated using Eq. (Y_HG)
  TAX_H[1] <<- (TAX[1] -  (TAX_F[1]) -  (TAX_C[1]))  #Calculated using Eq. (TAX)
  Y_H[1] <<- Y_HG[1]-TAX_H[1]  #Calculated using Eq. (Y_H)
  alpha_0 <<- (I[1]) / ((K[1] / (1 + g_K[1]))) - (alpha_1*r[1])  #Calculated using Eq. (I)
  tau_H <<- (TAX_H[1]) / ((Y_HG[1] / (1 + g_YHG[1])))  #Calculated using Eq. (TAX_H)
}

# -- Scenarios --
# -- Scenario 1: Baseline --
Parameters_scenario1 <- function() {
}

# -- Scenario 2: Green investment shock --
Parameters_scenario2 <- function() {
  int_G <<- 0.06
int_C <<- 0.10
beta_0 <<- 0.33
}

# -- Scenario 3: Degrowth shock --
Parameters_scenario3 <- function() {
  c_1 <<- 0.7
alpha_0 <<- 0.02
}
eq_body <- deparse(body(Equations))
var_names <- unique(na.omit(sub('^\\s*([A-Za-z_][A-Za-z0-9_]*)\\[t\\]\\s*<<-.*','\\1',
  eq_body[grepl('\\[t\\]\\s*<<-', eq_body)])))
Symbols_var      <- var_names
Symbols_var_sort <- sort(var_names)
iv_body  <- deparse(body(Parameters_InitialValues))
iv_vars  <- unique(na.omit(sub('^\\s*([A-Za-z_][A-Za-z0-9_]*)\\[1\\]\\s*<<-.*','\\1',
  iv_body[grepl('\\[1\\]\\s*<<-', iv_body)])))
par_names <- setdiff(iv_vars, var_names)
Symbols_par_sort <- sort(par_names)
all_vars <- unique(c(var_names, iv_vars))
genv <- globalenv()
ensure_vectors <- function() {
  for (v in all_vars) {
    cur <- if (exists(v, envir=genv, inherits=FALSE)) get(v, envir=genv) else NULL
    if (is.null(cur) || !is.numeric(cur) || length(cur) != T) {
      vec <- vector('numeric', length=T)
      if (!is.null(cur) && is.numeric(cur) && length(cur)>=1)
        vec[seq_len(min(length(cur),T))] <- cur[seq_len(min(length(cur),T))]
      assign(v, vec, envir=genv)
    }
  }
}
results <- list()
for (j in 1:3) {
  for (v in all_vars) assign(v, vector('numeric', length = T), envir=genv)
  for (iterations in 1:30) {Parameters_InitialValues()}
  ensure_vectors()
  for (i in 2:T) {
    if (j==2 & i>=5) {Parameters_scenario2()}
    if (j==3 & i>=5) {Parameters_scenario3()}
    for (iterations in 1:30) {Equations(t=i)}
  }
  results[[j]] <- as.data.frame(setNames(
    lapply(var_names, function(v) get(v, envir=genv, inherits=FALSE)),
    var_names))
  # -- Tables (equation order) --
  tablename <- paste0('Variables', j)
  values <- setNames(data.frame(matrix(ncol=length(Symbols_var), nrow=T)), Symbols_var)
  for (v in seq_along(Symbols_var)) values[,v] <- get(Symbols_var[v], envir=genv, inherits=FALSE)
  assign(tablename, round(values, 4))
  # -- Tables (alphabetical order) --
  tablename <- paste0('Variables_sorted', j)
  values <- setNames(data.frame(matrix(ncol=length(Symbols_var_sort), nrow=T)), Symbols_var_sort)
  for (v in seq_along(Symbols_var_sort)) values[,v] <- get(Symbols_var_sort[v], envir=genv, inherits=FALSE)
  assign(tablename, round(values, 6))
  # -- Parameter table --
  tablename <- paste0('Parameters_sorted', j)
  values <- setNames(data.frame(matrix(ncol=length(Symbols_par_sort), nrow=1)), Symbols_par_sort)
  for (v in seq_along(Symbols_par_sort)) {
    val <- tryCatch(get(Symbols_par_sort[v], envir=genv, inherits=FALSE), error=function(e) NA)
    values[,v] <- if (length(val)==1) val else val[1]
  }
  assign(tablename, round(values, 4))
  rm(values)
  # -- Save CSV files --
  write.csv(get(paste0('Variables',j)),        paste0('Variables',j,'.csv'))
  write.csv(get(paste0('Variables_sorted',j)), paste0('Variables-sorted',j,'.csv'))
  write.csv(get(paste0('Parameters_sorted',j)),paste0('Parameters-sorted',j,'.csv'))
  cat('Scenario', j, 'done\n')
}

# -- Charts --
if (!requireNamespace('ggplot2', quietly=TRUE)) install.packages('ggplot2')
library(ggplot2)
years      <- 2023 + seq_len(T) - 1
sc_names   <- c("Baseline", "Green investment shock", "Degrowth shock")
chart_cols <- c("#000000","#009E73","#D55E00")
chart_lts  <- c("solid","solid","solid")
Chart3 <- function(fig_title, variable, label, min, max,
                   sce1=1, sce2=2, sce3=3, legend_x=0.25, legend_y=0.92) {
  sc_sel <- c(sce1, sce2, sce3)
  df <- do.call(rbind, lapply(sc_sel, function(j) {
    data.frame(Year=years, Value=results[[j]][[variable]],
               Scenario=sc_names[j], stringsAsFactors=FALSE)
  }))
  df$Scenario <- factor(df$Scenario, levels=sc_names[sc_sel])
  # DEFINE interface style (matches interface.R theme_define)
  define_theme <- theme_bw(base_size=7, base_family='Helvetica') %+replace%
    theme(
      panel.background  = element_rect(fill='white',    colour=NA),
      panel.border      = element_rect(colour='#2C3E4A', fill=NA, linewidth=0.45),
      plot.background   = element_rect(fill='white',    colour=NA),
      panel.grid.major  = element_line(colour='#EAECEE', linewidth=0.25),
      panel.grid.minor  = element_blank(),
      axis.ticks        = element_line(colour='#2C3E4A', linewidth=0.3),
      axis.ticks.length = unit(-2.5, 'pt'),
      axis.text.x       = element_text(colour='#2C3E4A', size=6,  margin=margin(t=4)),
      axis.text.y       = element_text(colour='#2C3E4A', size=6,  margin=margin(r=4)),
      axis.title.x      = element_text(colour='#2C3E4A', size=5.5, margin=margin(t=4)),
      axis.title.y      = element_text(colour='#2C3E4A', size=5.5, angle=90, margin=margin(r=4)),
      plot.title        = element_text(colour='#2E8B57', size=7,  face='bold', hjust=0, margin=margin(b=3)),
      legend.position   = 'bottom',
      legend.direction  = 'horizontal',
      legend.background = element_rect(fill='white', colour=NA),
      legend.key        = element_rect(fill=NA, colour=NA),
      legend.key.width  = unit(16, 'pt'),
      legend.key.height = unit(5,  'pt'),
      legend.text       = element_text(size=5.5, colour='#2C3E4A'),
      legend.title      = element_blank(),
      legend.spacing.x  = unit(3, 'pt'),
      legend.margin     = margin(t=2, b=1),
      plot.margin       = margin(5, 8, 4, 5)
    )
  p <- ggplot(df, aes(x=Year, y=Value, colour=Scenario, linetype=Scenario, group=Scenario)) +
    geom_line(linewidth=0.6, lineend='round', na.rm=TRUE) +
    scale_colour_manual(values=chart_cols[sc_sel]) +
    scale_linetype_manual(values=chart_lts[sc_sel]) +
    scale_y_continuous(limits=c(min, max), expand=expansion(mult=c(0.04, 0.06))) +
    scale_x_continuous(expand=expansion(mult=c(0.01, 0.02))) +
    labs(title=variable, y=label, x='Year') +
    define_theme +
    guides(colour=guide_legend(nrow=2, byrow=TRUE, override.aes=list(linewidth=0.9)))
  ggsave(fig_title, p, width=3.5, height=2.5, dpi=300, units='in')
  invisible(p)
}
